--- 判断道具列表是否满足
---@param itemList V_Item[]
function LxItemCtrl:CheckItemListEnough(itemList,showTips, uiName,callBack)
    showTips = showTips and true or false
    local isEnough = true
    for i,v in ipairs(itemList) do
        if not self:CheckItemEnough(v,showTips, uiName) then
            isEnough = false
            if callBack then callBack(v) end
            break
        end
    end
    return isEnough
end

--- 判断道具是否满足
---@param item V_Item
function LxItemCtrl:CheckItemEnough(item,showTips, uiName)
    local refId = item.refId
    local hasNum = ModuleCenter.Item:GetItemCount(refId)
    local isEnough = hasNum >= item.num
    if not isEnough and showTips then
        ShowPanel(UiNames.ItemOrigin, {refId = refId, from = uiName})
    end
    return isEnough
end

