function LxItemCtrl:_InnerInitTypeDataList()
    if self._isInitTypeDataList then return end
    self._isInitTypeDataList = true
    local typeDate
    local initHeroMirrorItemMap = {}
    local initHeroSkinItems = {}
    local initPayDiscountItems = {}

    self._initHeroMirrorItemMap = initHeroMirrorItemMap
    self._initHeroSkinItems = initHeroSkinItems
    self._initPayDiscountItems = initPayDiscountItems

    local typeDateInitFunc = {
        [Item_Types.T_HeroSoul] = function(ref)
            typeDate = string.split(ref.typeDate, "=")
            initHeroMirrorItemMap[ref.refId] = {
                raceType = checknumber(typeDate[1]),
                star = checknumber(typeDate[2]),
            }
        end,

        [Item_Types.T_HeroChip] = function(ref)
            typeDate = string.split(ref.typeDate, "=")
            local heroRefId = checknumber(typeDate[1])
            local heroType = LxDataHelper.GetHeroEff2HeroType(heroRefId)
            local skinTime = checknumber(typeDate[2])
            local initHeroSkins = initHeroSkinItems[heroType]
            if not initHeroSkins then
                initHeroSkins = {}
                initHeroSkinItems[heroType] = initHeroSkins
            end
            initHeroSkins[ref.refId] = {
                heroType = heroType,
                heroRefId = heroRefId,
                skinTime = skinTime,
                --- 非永久
                isPermanent = skinTime < 0,
            }
        end,

        [Item_Types.T_PayDiscount] = function(ref)
            typeDate = string.split(ref.typeDate, "=")
            local welfareRefId1 = checknumber(typeDate[1])
            local welfareRefId2 = checknumber(typeDate[2])
            local itemDiscountMap = initPayDiscountItems[welfareRefId1]
            if not itemDiscountMap then
                itemDiscountMap = {}
                initPayDiscountItems[welfareRefId1] = itemDiscountMap
            end
            itemDiscountMap[ref.refId] = welfareRefId2
        end
    }

    for k,v in pairs(GameTable.PlayerItemRef) do
        local initFunc = typeDateInitFunc[v.type]
        if initFunc ~= nil then
            initFunc(v)
        end
    end
end

