--- 获取英雄镜像类型的 typeData 111 类型
function LxItemCtrl:GetHeroMirrorItemTypeData()
    if not self._isInitTypeDataList then
       self:_InnerInitTypeDataList()
    end
    return self._initHeroMirrorItemMap
end

function LxItemCtrl:GetHeroMirrorItemByRaceTypeAndStar(raceType,star)
    local itemDatas = {}
    local typeDatas = self:GetHeroMirrorItemTypeData()
    local tRaceType
    for k,v in pairs(typeDatas) do
        tRaceType = v.raceType
        if tRaceType == 0 or tRaceType == raceType then
            if v.star == star then
                table.insert(itemDatas, {
                    parseData = v,
                    refId = k,
                })
            end
        end

    end
    return itemDatas
end

