function LxItemCtrl:CheckHeroSkinTimeIsEnough(heroRefId)
    local itemModule = ModuleCenter.Item
    local datas = self:GetHeroSkinItemsByRefId(heroRefId)
    if datas then
        for itemId,v in pairs(datas) do
            if not v.isPermanent and itemModule:GetItemCount(itemId) > 0 then
                return true,itemId
            end
        end
    end
    return false
end

