---支付折扣道具
function LxItemCtrl:GetPayDiscountData(refId)
    if not self._isInitTypeDataList then
        self:_InnerInitTypeDataList()
    end
    local itemList = self._initPayDiscountItems[refId]
    if not itemList then return nil end
    local ItemModule = ModuleCenter.Item
    for k,v in pairs(itemList) do
        if ItemModule:GetItemCount(k) > 0 then
            return v,k
        end
    end
    return nil
end
