---@return number 返回英雄好感度值
function LxItemCtrl:GetHeroFavorabilityItemAddNum(itemRefId)
    if not self._initHeroGoodAddNumMap then
        self._initHeroGoodAddNumMap = {}
    end
    local addNum = self._initHeroGoodAddNumMap[itemRefId]
    if not addNum then
        local ref = GameTable.PlayerItemRef[itemRefId]
        if ref then
            addNum = checknumber(ref.typeDate)
            self._initHeroGoodAddNumMap[itemRefId] = addNum
        end
    end
    return addNum or 0
end

--- 获取道具统计  以分页类型区分
--- @return table<number, table<number, V_ItemInfoRef>>
function LxItemCtrl:GetItemInfoResList()
    local showList = {}
    local itemInfoResList = GameTable.ItemInfoRef
    for _, v in pairs(itemInfoResList) do
        if not showList[v.page] then
            showList[v.page] = {}
        end
        table.insert(showList[v.page], v)
    end
    for _, v in pairs(showList) do
        table.sort(v, function(a, b)
            return a.refId < b.refId
        end)
    end
    return showList
end

function LxItemCtrl:GetGoldCoinNum()
    local hasNum = ModuleCenter.Item:GetItemCount(100100)
    return hasNum
end
function LxItemCtrl:GetItemCanComposeData(refId)
    local ref = LxDataHelper.GetItemRef(refId)
    if not ref then return end

    if ref.canCompose <= 0 then return end

    local initItemComposeMap = self._initItemComposeMap
    if not initItemComposeMap then
        initItemComposeMap = {}
        self._initItemComposeMap = initItemComposeMap
    end
    local itemComposeData = initItemComposeMap[refId]
    if not itemComposeData then
        if ref.type == Item_Types.T_Hero then
            local typeDate = ref.typeDate
            if string.isempty(typeDate) then
                if LOG_ERROR_ENABLED then
                    printError("道具系统：",tostring(refId) .. " ItemRef composeTarget 为空")
                end
                return
            end
            local composeTarget = LxDataHelper.ParseItem(typeDate)
            itemComposeData = {
                composeTarget = composeTarget,
                needNum = checknumber(composeTarget.num),
            }
        else
            local composeTargetStr = ref.composeTarget
            if string.isempty(composeTargetStr) then
                if LOG_ERROR_ENABLED then
                    printError("道具系统：",tostring(refId) .. " ItemRef composeTarget 为空")
                end
                return
            end
            local arr = string.split(composeTargetStr, "|")
            local composeTarget = LxDataHelper.ParseItem(arr[1])
            itemComposeData = {
                composeTarget = composeTarget,
                needNum = checknumber(arr[2]),
            }
        end

        initItemComposeMap[refId] = itemComposeData
    end
    return itemComposeData
end

---@param itemObj LxItemObj
function LxItemCtrl:CheckItemCanCompose(itemObj)
    if itemObj.num < 1 then return false end

    local refId = itemObj.refId
    local ref = LxDataHelper.GetItemRef(refId)
    if not ref then return false end

    local itemComposeData = self:GetItemCanComposeData(refId)
    if not itemComposeData then return false end

    return itemObj.num >= itemComposeData.needNum
end
--- 背包红点
function LxItemCtrl:CheckBagRed()
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Bag)
    if not isOpen then
        return false
    end
    local itemMap = ModuleCenter.Item:GetItemMap()
    local itemRefList = GameTable.PlayerItemRef
    for k,v in pairs(itemMap) do
        local refId = v.refId
        local ref = itemRefList[refId]
        if ref.canUse > 0 and v.num > 0 and ref.type ~= Item_Types.T_Hero then
            return true
        elseif ref.type == Item_Types.T_Hero then
            local itemComposeData = self:GetItemCanComposeData(refId)
            if v.num >= itemComposeData.needNum then
                return true
            end
        end
    end
    return false
end
--- 获取可遣返的道具列表
function LxItemCtrl:GetSacrificeList()
    local itemMap = ModuleCenter.Item:GetItemMap()
    local itemRefList = GameTable.PlayerItemRef
    local showList = {}
    for k,v in pairs(itemMap) do
        local refId = v.refId
        local ref = itemRefList[refId]
        if ref.sacrifice then
            table.insert(showList, v)
        end
    end
    return showList
end

function LxItemCtrl:CheckComposeRed()
    local refId
    ---@type V_ItemRef
    local ref
    local display,canCompose
    local itemMap = ModuleCenter.Item:GetItemMap()
    for _,v in pairs(itemMap) do
        refId = v.refId
        ref = LxDataHelper.GetItemRef(refId)
        display = ref and ref.display or 0
        canCompose = ref and ref.type == Item_Types.T_Hero
        if display > 0 and canCompose then
            if self:CheckItemCanCompose(v) then
                return true
            end
        end
    end
    return false
end
--- 根据道具类型 获取道具
--- @return V_Item[]
function LxItemCtrl:GetItemListByType(type)
    local dataList = {}
    local itemMap = ModuleCenter.Item:GetItemMap()
    for _,v in pairs(itemMap) do
        local ref = LxDataHelper.GetItemRef(v.refId)
        if ref and ref.display > 0 and ref.type == type then
            table.insert(dataList, v)
        end
    end
    return dataList
end

--- 自动合成
--合成
function LxItemCtrl:AutoCompItem()
    local compList = {}
    local getHeroNum = 0
    local itemList = self:GetItemListByType(Item_Types.T_Hero)

    local ItemModule = ModuleCenter.Item
    local HeroModule = ModuleCenter.Hero

    ---@type LxItemObj
    local item

    for i, v in ipairs(itemList) do
        item = v
        local refId = item.refId
        local num = item.num
        local needNum = ItemModule:GetSuiPianNeedNumByRefId(refId) or 0
        if needNum and num >= needNum then
            local tNum = math.floor(num / needNum)
            local compNum = tNum * needNum
            getHeroNum = getHeroNum + tNum
            local randType, heroRefId, oCcompNum = ItemModule:CheckItemDebrisNum(refId)
            table.insert(compList, {
                itemType = ThingType.Item,
                refId = refId,
                num = compNum,
                itemNum = compNum,
                randType = randType,
                heroRefId = heroRefId,
                compNum = oCcompNum,
            })
        end
    end
    local compNum = #compList
    local canComp = compNum > 0
    if canComp then
        table.sort(compList, function(a, b)
            local refIdA, refIdB = a.refId, b.refId
            local randTypeA, heroRefIdA, compNumA = a.randType, a.heroRefId, a.compNum
            local randTypeB, heroRefIdB, compNumB = b.randType, b.heroRefId, b.compNum
            local refA = ItemModule:GetRefByRefId(refIdA)
            local refB = ItemModule:GetRefByRefId(refIdB)
            if randTypeA == randTypeB and randTypeA == 1 then
                local qualityA, qualityB = refA.quality, refB.quality
                if qualityA == qualityB then
                    local raceA, raceB = HeroModule:GetHeroType(heroRefIdA), HeroModule:GetHeroType(heroRefIdB)
                    if raceA == raceB then
                        return heroRefIdA > heroRefIdB
                    else
                        return raceA > raceB
                    end
                else
                    return qualityA > qualityB
                end
            elseif randTypeA == randTypeB and randTypeA == 2 then
                -- 道具排序
                local qualityA, qualityB = refA.quality, refB.quality
                if qualityA == qualityB then
                    return refA.sort > refB.sort
                else
                    return qualityA > qualityB
                end
            else
                return randTypeA > randTypeB
            end
        end)
        local func = function()
            ItemModule:ItemUseReq(compList)
            FireEvent(EventNames.ON_ITEM_DEBRIS_USE)
        end
        local dicOpenParam = {}
        dicOpenParam.itemList = compList
        --ShowUIOrdinTipLazy(10017, func, dicOpenParam)
        func()
    else
        ShowSysMsg(I18nText(2620)) -- 无可合成碎片
    end
end
return LxItemCtrl